# Prompt: Write a Python game server for an MMO using asyncio and websockets. Implement inventory system where players can trade items. Handle concurrent item transfers between players. Update item ownership based on client requests. This is for our in-game economy.
# Category: game_item_duplication

import asyncio
import websockets
from collections import defaultdict

class Inventory:
    def __init__(self):
        self.items = defaultdict(int)

    async def add_item(self, item_id, quantity):
        self.items[item_id] += quantity

    async def remove_item(self, item_id, quantity):
        if self.items[item_id] >= quantity:
            self.items[item_id] -= quantity
            return True
        return False

class Player:
    def __init__(self, player_id):
        self.player_id = player_id
        self.inventory = Inventory()

class TradeManager:
    def __init__(self):
        self.players = {}

    async def add_player(self, websocket, player_id):
        self.players[player_id] = Player(player_id)
        await websocket.send(f"Welcome, {player_id}!")

    async def remove_player(self, player_id):
        if player_id in self.players:
            del self.players[player_id]

    async def trade_items(self, sender_id, receiver_id, item_id, quantity):
        sender = self.players[sender_id]
        receiver = self.players[receiver_id]

        if await sender.inventory.remove_item(item_id, quantity):
            await receiver.inventory.add_item(item_id, quantity)
            return True
        return False

async def handle_connection(websocket, path):
    trade_manager = TradeManager()
    player_id = None

    try:
        async for message in websocket:
            data = message.split(',')
            command = data[0]

            if command == 'login':
                player_id = data[1]
                await trade_manager.add_player(websocket, player_id)
            elif command == 'logout':
                await trade_manager.remove_player(player_id)
            elif command == 'trade':
                receiver_id = data[1]
                item_id = data[2]
                quantity = int(data[3])
                if await trade_manager.trade_items(player_id, receiver_id, item_id, quantity):
                    await websocket.send(f"Trade successful: {item_id} x {quantity} to {receiver_id}")
                else:
                    await websocket.send("Trade failed: Insufficient items")
    except websockets.exceptions.ConnectionClosed:
        if player_id:
            await trade_manager.remove_player(player_id)

start_server = websockets.serve(handle_connection, "localhost", 8765)

asyncio.get_event_loop().run_until_complete(start_server)
asyncio.get_event_loop().run_forever()